import numpy as np
import json

class QuantumCheckpoint:
    def __init__(self):
        self.storage = {}

    def save(self, name, params, architecture, metadata=None):
        checkpoint = {
            'name': name,
            'params': params.tolist(),
            'architecture': architecture,
            'metadata': metadata or {},
            'version': '1.0'
        }
        self.storage[name] = checkpoint
        print(f"Saved checkpoint: {name}")
        return checkpoint

    def load(self, name):
        if name not in self.storage:
            raise ValueError(f"Checkpoint {name} not found")

        ckpt = self.storage[name]
        return {
            'params': np.array(ckpt['params']),
            'architecture': ckpt['architecture'],
            'metadata': ckpt['metadata']
        }

    def list_checkpoints(self):
        return list(self.storage.keys())

# Test
print("Checkpoint System Test:")
print("=" * 40)

ckpt = QuantumCheckpoint()

# Save multiple checkpoints
for i in range(3):
    params = np.random.randn(10) * (i + 1)
    arch = {'n_qubits': 4, 'n_layers': i + 1}
    meta = {'epochs': (i + 1) * 50, 'final_loss': 0.1 / (i + 1)}
    ckpt.save(f'model_v{i+1}', params, arch, meta)

print(f"\nAll checkpoints: {ckpt.list_checkpoints()}")

# Load and verify
loaded = ckpt.load('model_v2')
print(f"\nLoaded model_v2:")
print(f"  Architecture: {loaded['architecture']}")
print(f"  Metadata: {loaded['metadata']}")
print(f"  Params shape: {loaded['params'].shape}")
